  1	import * as React from 'react';
  2	import { kialiStyle } from 'styles/StyleUtils';
  3	import { legendData, MeshLegendItem, MeshLegendItemRow } from './MeshLegendData';
  4	import { Button, ButtonVariant, Tooltip } from '@patternfly/react-core';
  5	import { PFColors } from 'components/Pf/PfColors';
  6	import { KialiIcon } from 'config/KialiIcon';
  7	import { useKialiTranslation } from 'utils/I18nUtils';
  8	
  9	interface MeshLegendProps {
 10	  closeLegend: () => void;
 11	}
 12	
 13	const legendBoxStyle = kialiStyle({
 14	  width: '225px',
 15	  backgroundColor: PFColors.BackgroundColor100,
 16	  border: `1px solid ${PFColors.BorderColor100}`,
 17	  overflowY: 'auto',
 18	  zIndex: 3
 19	});
 20	
 21	const headerStyle = kialiStyle({
 22	  display: 'flex',
 23	  alignItems: 'center',
 24	  justifyContent: 'space-between',
 25	  borderBottom: `1px solid ${PFColors.BorderColor100}`,
 26	  padding: '0.5rem 0 0.5rem 1rem',
 27	  fontWeight: 'bold'
 28	});
 29	
 30	const bodyStyle = kialiStyle({
 31	  padding: '0 0.5rem 1rem 1rem'
 32	});
 33	
 34	const keyStyle = kialiStyle({
 35	  minWidth: '70px',
 36	  width: '70px'
 37	});
 38	
 39	const legendItemStyle = kialiStyle({
 40	  display: 'flex',
 41	  flexDirection: 'row',
 42	  alignItems: 'center',
 43	  padding: '0.25rem 0.25rem 0 0.25rem'
 44	});
 45	
 46	const legendItemLabelStyle = kialiStyle({
 47	  fontWeight: 'normal'
 48	});
 49	
 50	const legendColumnHeadingStyle = kialiStyle({
 51	  fontWeight: 'bold',
 52	  paddingTop: '1.25rem'
 53	});
 54	
 55	const legendLogoStyle = kialiStyle({
 56	  width: '2rem',
 57	  height: '2rem',
 58	  marginBottom: '0.125rem'
 59	});
 60	
 61	export const MeshLegend: React.FC<MeshLegendProps> = (props: MeshLegendProps) => {
 62	  const { t } = useKialiTranslation();
 63	
 64	  const renderGraphLegendList = (legendData: MeshLegendItem[]): React.ReactNode => {
 65	    return (
 66	      <>
 67	        {legendData.map((legendItem: MeshLegendItem) => (
 68	          <div key={legendItem.title} className={legendColumnHeadingStyle}>
 69	            {t(legendItem.title)}
 70	
 71	            {legendItem.data.map((legendItemRow: MeshLegendItemRow) =>
 72	              renderLegendIconAndLabel(legendItemRow, legendItem.isLogo)
 73	            )}
 74	          </div>
 75	        ))}
 76	      </>
 77	    );
 78	  };
 79	
 80	  const renderLegendIconAndLabel = (legendItemRow: MeshLegendItemRow, isLogo?: boolean): React.ReactNode => {
 81	    return (
 82	      <div key={legendItemRow.icon} className={legendItemStyle}>
 83	        <span className={keyStyle}>
 84	          <img alt={legendItemRow.label} src={legendItemRow.icon} className={isLogo ? legendLogoStyle : ''} />
 85	        </span>
 86	
 87	        <span className={legendItemLabelStyle}>{t(legendItemRow.label)}</span>
 88	      </div>
 89	    );
 90	  };
 91	
 92	  return (
 93	    <div className={legendBoxStyle} data-test="graph-legend">
 94	      <div className={headerStyle}>
 95	        <span>{t('Legend')}</span>
 96	        <Tooltip content={t('Close Legend')}>
 97	          <Button id="legend_close" variant={ButtonVariant.plain} onClick={props.closeLegend}>
 98	            <KialiIcon.Close />
 99	          </Button>
100	        </Tooltip>
101	      </div>
102	
103	      <div className={bodyStyle}>{renderGraphLegendList(legendData)}</div>
104	    </div>
105	  );
106	};

